const items = $input.all();
if (items.length === 0) return [];
if (!Array.isArray(items[0].json)) {
  return items.map(item => ({ json: item.json }));
}
const arr = items[0].json;
return arr.filter(Boolean).map(contact => ({ json: contact }));

