return [{ json: { ...item, _wa_number: waNumber, mensaje } }];

const waResp = $('Enviar WhatsApp').first().json;
const prep   = $('Preparar Body WA').first().json;

const respStr = JSON.stringify(waResp);
const failed  = waResp.error !== undefined
             || respStr.includes('"exists":false')
             || respStr.includes('Bad Request')
             || respStr.includes('"status":404')
             || respStr.includes('"status":500');

const now_str = new Date().toISOString();

return [{ json: {
  phone:       prep.phone,
  rubro:       prep.rubro,
  mensaje:     prep.mensaje,
  name:        prep.name,
  contact_id:  prep.id,
  user_id:     prep.user_id,
  now_str:     now_str,
  etapa_final: failed ? 'no_enviado' : 'enviado'
} }];
